use criterion::{black_box, criterion_group, criterion_main, Criterion};
use multivarious::common_types::{Matrix, Vector};
use ndarray::{Array1, Array2};
use ndarray::prelude::*;

fn benchmark_matrix_creation(c: &mut Criterion) {
    c.bench_function("create_matrix_100x100", |b| {
        b.iter(|| {
            let mat: Matrix = Array2::zeros((100, 100));
            black_box(mat);
        })
    });

    c.bench_function("create_matrix_1000x1000", |b| {
        b.iter(|| {
            let mat: Matrix = Array2::zeros((1000, 1000));
            black_box(mat);
        })
    });
}

fn benchmark_matrix_multiplication(c: &mut Criterion) {
    let a = Array2::<f64>::zeros((100, 100));
    let b = Array2::<f64>::zeros((100, 100));

    c.bench_function("matrix_mul_100x100", |b| {
        b.iter(|| {
            let result = a.dot(&b);
            black_box(result);
        })
    });
}

fn benchmark_vector_operations(c: &mut Criterion) {
    let vec: Vector = Array1::linspace(0.0, 100.0, 1000);

    c.bench_function("vector_sum_1000", |b| {
        b.iter(|| {
            let sum = vec.sum();
            black_box(sum);
        })
    });

    c.bench_function("vector_mean_1000", |b| {
        b.iter(|| {
            let mean = vec.mean().unwrap();
            black_box(mean);
        })
    });
}

criterion_group!(
    benches,
    benchmark_matrix_creation,
    benchmark_matrix_multiplication,
    benchmark_vector_operations
);
criterion_main!(benches);

