#!/bin/bash
# Development helper script for multivarious-rs

set -e

# Colors for output
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
NC='\033[0m' # No Color

function print_help {
    echo "Development helper script for multivarious-rs"
    echo ""
    echo "Usage: ./scripts/dev.sh [command]"
    echo ""
    echo "Commands:"
    echo "  test        Run all tests"
    echo "  bench       Run all benchmarks"
    echo "  lint        Run clippy lints"
    echo "  fmt         Format code with rustfmt"
    echo "  check       Run cargo check"
    echo "  build       Build in release mode"
    echo "  coverage    Generate test coverage report"
    echo "  docs        Generate and open documentation"
    echo "  clean       Clean build artifacts"
    echo "  all         Run fmt, lint, test, and build"
}

function run_tests {
    echo -e "${GREEN}Running tests...${NC}"
    cargo test --all-features
}

function run_benchmarks {
    echo -e "${GREEN}Running benchmarks...${NC}"
    cargo bench
}

function run_lint {
    echo -e "${GREEN}Running clippy...${NC}"
    cargo clippy --all-features -- -D warnings
}

function run_fmt {
    echo -e "${GREEN}Formatting code...${NC}"
    cargo fmt
}

function run_check {
    echo -e "${GREEN}Running cargo check...${NC}"
    cargo check --all-features
}

function run_build {
    echo -e "${GREEN}Building in release mode...${NC}"
    cargo build --release --all-features
}

function run_coverage {
    echo -e "${GREEN}Generating coverage report...${NC}"
    cargo tarpaulin --out Html --output-dir target/coverage
    echo -e "${GREEN}Coverage report generated at: target/coverage/tarpaulin-report.html${NC}"
}

function run_docs {
    echo -e "${GREEN}Generating documentation...${NC}"
    cargo doc --no-deps --all-features --open
}

function run_clean {
    echo -e "${GREEN}Cleaning build artifacts...${NC}"
    cargo clean
}

function run_all {
    run_fmt
    run_lint
    run_tests
    run_build
    echo -e "${GREEN}All checks passed!${NC}"
}

# Main script logic
case "$1" in
    test)
        run_tests
        ;;
    bench)
        run_benchmarks
        ;;
    lint)
        run_lint
        ;;
    fmt)
        run_fmt
        ;;
    check)
        run_check
        ;;
    build)
        run_build
        ;;
    coverage)
        run_coverage
        ;;
    docs)
        run_docs
        ;;
    clean)
        run_clean
        ;;
    all)
        run_all
        ;;
    *)
        print_help
        ;;
esac

