/// Method for computing SVD
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum SvdMethod {
    /// Standard full SVD decomposition
    Full,
    /// Thin SVD (economy size decomposition)
    Thin,
    /// Truncated SVD with specified number of components
    Truncated(usize),
    /// Randomized SVD for large matrices
    Randomized {
        /// Number of components to compute
        n_components: usize,
        /// Number of power iterations for accuracy
        n_iter: usize,
        /// Random seed for reproducibility
        seed: Option<u64>,
    },
}

impl fmt::Display for SvdMethod {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            SvdMethod::Full => write!(f, "Full SVD"),
            SvdMethod::Thin => write!(f, "Thin SVD"),
            SvdMethod::Truncated(k) => write!(f, "Truncated SVD (k={})", k),
            SvdMethod::Randomized { n_components, n_iter, .. } => {
                write!(f, "Randomized SVD (k={}, iter={})", n_components, n_iter)
            }
        }
    }
}

/// Result of SVD decomposition
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SvdResult {
    /// Left singular vectors (U matrix)
    pub u: Matrix,
    /// Singular values (diagonal of S)
    pub s: Vector,
    /// Right singular vectors (V^T matrix)
    pub vt: Matrix,
    /// Method used for decomposition
    pub method: SvdMethod,
    /// Number of iterations (for iterative methods)
    pub n_iter: Option<usize>,
    /// Explained variance ratio for each component
    pub explained_variance_ratio: Option<Vector>,
}

impl SvdResult {
    /// Reconstruct the original matrix from SVD components
    pub fn reconstruct(&self) -> Matrix {
        let s_diag = Matrix::from_diag(&self.s);
        self.u.dot(&s_diag).dot(&self.vt)
    }

    /// Get the number of components
    pub fn n_components(&self) -> usize {
        self.s.len()
    }

    /// Get the total variance explained
    pub fn total_variance_explained(&self) -> Option<f64> {
        self.explained_variance_ratio.as_ref().map(|evr| evr.sum())
    }

    /// Get cumulative explained variance ratio
    pub fn cumulative_variance_ratio(&self) -> Option<Vector> {
        self.explained_variance_ratio.as_ref().map(|evr| {
            let mut cumsum = Vector::zeros(evr.len());
            let mut sum = 0.0;
            for (i, &val) in evr.iter().enumerate() {
